import { NotificationContext } from '@/src/contexts/Nofitication.context';
import { notify } from '../helpers/notification.helpers';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

interface UseNotification {
  notificationElem: HTMLHuelNotificationElement | null;
  triggerNotification: (props: NotificationProps) => Promise<void>;
}

const NotificationContext = createContext(null);

const useNotification = (): UseNotification => {
  const notificationElem = useContext(NotificationContext);
  const [triggerNotification, setTriggerNotification] = useState<((props: NotificationProps) => Promise<void>) | null>(null);

  const notify = async (props: NotificationProps) => => {
    if (!notificationElem) return;

    const { heading, subheading, type } = props;
    await notificationElem.open({
      heading,
      subheading,
      type,
    });
  };

  setTriggerNotification(notify);

  return { notificationElem, triggerNotification };
};

